bool XtensaInstructionSelector::select(MachineInstr &I) {

  MachineBasicBlock &MBB = *I.getParent();
  MachineFunction &MF = *MBB.getParent();
  MachineRegisterInfo &MRI = MF.getRegInfo();


  if (selectImpl(I, *CoverageInfo))
    return true;

  MachineInstr *MI = nullptr;
  using namespace TargetOpcode;

  return false;
}




namespace llvm {
InstructionSelector *createXtensaInstructionSelector(const XtensaTargetMachine &TM,
                                                   XtensaSubtarget &Subtarget,
                                                   XtensaRegisterBankInfo &RBI) {
  return new XtensaInstructionSelector(TM, Subtarget, RBI);
}
} // end namespace llvm
